import React from 'react';

const Introduction = () => {
  return (
    <section
      id="Introduction"
      className="min-h-screen flex items-center px-5 pt-24"
      style={{
        fontFamily: "'Orbitron', sans-serif",
        background:
          'linear-gradient(rgba(13,110,253,0.25), rgba(10,25,47,0.9)), url(/images/background-image.jpg) center/cover no-repeat',
      }}
    >
      <div className="flex flex-col md:flex-row items-center justify-between w-full max-w-5xl mx-auto gap-12">
        <div>
          <p className="text-xs font-bold mb-3 tracking-widest" style={{ color: '#0d6efd' }}>
            ✕ PLAYER ONE
          </p>

          <h1 className="text-white text-5xl font-bold">
            ALIHAKIM M. DIMACALING
          </h1>

          <p className="text-gray-300 mt-3 italic">
            University Student | Game Enthusiast | Aspiring IT Professional
          </p>

          <p className="text-gray-400 mt-4">
            Pursuing BSIT major in Web Technology.
          </p>

          <div className="flex gap-4 mt-6">
            {['Projects', 'Contact'].map((btn) => (
              <a
                key={btn}
                href={`#${btn}`}
                className="px-5 py-2 text-sm font-bold rounded"
                style={{ background: '#0d6efd', color: '#fff' }}
              >
                {btn}
              </a>
            ))}
          </div>
        </div>

        <img
          src="/images/portrait-image.png"
          alt="portrait"
          className="rounded-full"
          style={{
            width: 250,
            height: 250,
            border: '4px solid #0d6efd',
          }}
        />
      </div>
    </section>
  );
};

export default Introduction;
